const { ApiPromise, WsProvider } = require("@polkadot/api");
const { ethers } = require("ethers");
require("dotenv").config();

// XCM Message generated by calc_xcm_message.js
const XCM_MESSAGE_HEX = "";

// XCM Precompile on Asset Hub (correct address)
const XCM_PRECOMPILE = "0x0000000000000000000000000000000000000804";

// Asset Hub RPC (EVM compatible)
const ASSET_HUB_RPC = "https://eth-rpc.polkadot.io/";

async function main() {
    console.log("=== XCM Message Test ===\n");

    // PART 1: Decode the XCM Message
    console.log("--- Part 1: Decoding XCM Message ---");
    try {
        const wsProvider = new WsProvider("wss://polkadot-asset-hub-rpc.polkadot.io");
        const api = await ApiPromise.create({ provider: wsProvider });

        const decoded = api.createType("XcmVersionedXcm", XCM_MESSAGE_HEX);
        console.log("Decoded XCM Message:");
        console.log(JSON.stringify(decoded.toHuman(), null, 2));

        await api.disconnect();
    } catch (e) {
        console.log("Decode Error:", e.message);
    }

    // PART 2: Test weighMessage via EVM
    console.log("\n--- Part 2: Testing weighMessage Precompile ---");
    try {
        const provider = new ethers.JsonRpcProvider(ASSET_HUB_RPC);

        // weighMessage(bytes memory message) returns (uint64 refTime, uint64 proofSize)
        const iface = new ethers.Interface([
            "function weighMessage(bytes) view returns (uint64, uint64)"
        ]);

        const callData = iface.encodeFunctionData("weighMessage", [XCM_MESSAGE_HEX]);

        console.log("Calling weighMessage on XCM Precompile...");
        console.log("Precompile:", XCM_PRECOMPILE);
        console.log("Message length:", XCM_MESSAGE_HEX.length / 2 - 1, "bytes");

        const result = await provider.call({
            to: XCM_PRECOMPILE,
            data: callData
        });

        console.log("Raw Result:", result);

        if (result && result !== "0x") {
            const [refTime, proofSize] = iface.decodeFunctionResult("weighMessage", result);
            console.log("\n✅ weighMessage SUCCESS!");
            console.log("   RefTime:", refTime.toString());
            console.log("   ProofSize:", proofSize.toString());
        } else {
            console.log("❌ Empty result from weighMessage");
        }
    } catch (e) {
        console.log("❌ weighMessage Error:", e.message);
        if (e.data) console.log("   Error data:", e.data);
    }

    console.log("\n=== Test Complete ===");
    process.exit(0);
}

main().catch(console.error);
